oxy_webhelp_navlinks = {"azr_cld_acc_add_mgmt_grp_oauth-d30753e18436":{"topics":[{"title":"Required permissions for creating custom role definitions","shortdesc":"<p class=\"shortdesc\">To onboard Azure subscriptions through a management group, <span class=\"ph\">RSC<\/span>         creates custom Azure role definitions at the management group scope. This requires you to         temporarily grant administrative permissions to the onboarding identity in the Azure         portal.<\/p>","href":"saas\/azr_mgmt_group_req_perms_custom_role_def.html","attributes":{"data-id":"azr_mgmt_group_req_perms_custom_role_def"},"menu":{"hasChildren":false},"tocID":"azr_mgmt_group_req_perms_custom_role_def-d30753e18447","topics":[]},{"title":"Granting permissions to user for management group onboarding","shortdesc":"<p class=\"shortdesc\">Before you onboard Azure subscriptions using a management group with the Configure         with OAuth method, grant the required permissions to the user performing the onboarding in         the Azure portal.<\/p>","href":"saas\/azr_granting_perms_users_mgmt_grp.html","attributes":{"data-id":"azr_granting_perms_users_mgmt_grp"},"menu":{"hasChildren":false},"tocID":"azr_granting_perms_users_mgmt_grp-d30753e18461","topics":[]},{"title":"Adding Azure subscriptions using management group with OAuth","shortdesc":"<p class=\"shortdesc\">Add multiple Azure subscriptions using an Azure management group with the Configure         with OAuth method. This method uses OAuth for authentication and automatically configures         the required roles and permissions.<\/p>","href":"saas\/azr_adding_subs_mgmt_grp_oauth.html","attributes":{"data-id":"azr_adding_subs_mgmt_grp_oauth"},"menu":{"hasChildren":false},"tocID":"azr_adding_subs_mgmt_grp_oauth-d30753e18472","topics":[]}]}};